// Economic Calendar Daily - Filter & Format
// Filters HIGH/MEDIUM impact events and key always-included events

const ALWAYS_INCLUDED = ['FOMC', 'NFP', 'CPI', 'PPI', 'GDP', 'PMI', 'ECB', 'BOE', 'BOJ'];
const INCLUDE_KEYWORDS = ALWAYS_INCLUDED.map(k => k.toLowerCase());

const today = new Date();
const dateStr = today.toLocaleDateString('es-ES', { 
  weekday: 'long', 
  year: 'numeric', 
  month: 'long', 
  day: 'numeric' 
});

// Get timezone offset for Madrid (Europe/Madrid)
const madridOffset = 2; // CEST offset (may vary by season)
const events = $input.all();

if (!events || events.length === 0) {
  return [{ json: { output: `CALENDARIO ECONÓMICO — ${dateStr}\n\nNo hay eventos económicos disponibles hoy.`, riskWindows: [] }}];
}

let calendarData;
try {
  calendarData = Array.isArray(events[0].json) ? events[0].json : [events[0].json];
} catch (e) {
  return [{ json: { output: `CALENDARIO ECONÓMICO — ${dateStr}\n\nError al procesar datos del calendario.`, riskWindows: [] }}];
}

// Filter for today
const todayStr = today.toISOString().split('T')[0];
const todayEvents = calendarData.filter(event => {
  if (!event.date) return false;
  const eventDate = event.date.split('T')[0];
  return eventDate === todayStr;
});

if (todayEvents.length === 0) {
  return [{ json: { output: `CALENDARIO ECONÓMICO — ${dateStr}\n\nNo hay eventos económicos programados para hoy.`, riskWindows: [] }}];
}

// Separate high and medium impact
events.forEach(e => console.log(JSON.stringify(e)));

const highImpact = todayEvents.filter(event => {
  const impact = (event.impact || '').toUpperCase();
  if (impact === 'HIGH') return true;
  // Always include key events regardless of impact
  const title = (event.title || event.event || '').toUpperCase();
  return INCLUDE_KEYWORDS.some(k => title.includes(k));
});

const mediumImpact = todayEvents.filter(event => {
  const impact = (event.impact || '').toUpperCase();
  const title = (event.title || event.event || '').toUpperCase();
  const isAlwaysIncluded = INCLUDE_KEYWORDS.some(k => title.includes(k));
  return impact === 'MEDIUM' && !isAlwaysIncluded;
});

// Extract risk windows (group by hour)
const riskWindows = [];
const hourMap = {};

[...highImpact, ...mediumImpact].forEach(event => {
  if (!event.date) return;
  const hour = new Date(event.date).getUTCHours();
  const key = hour;
  if (!hourMap[key]) {
    hourMap[key] = true;
    const windowStart = new Date(event.date);
    windowStart.setUTCMinutes(0, 0, 0);
    const windowEnd = new Date(windowStart);
    windowEnd.setUTCHours(hour + 1);
    riskWindows.push(`${String(hour + madridOffset).padStart(2, '0')}:00-${String(hour + madridOffset + 1).padStart(2, '0')}:00 CET`);
  }
});


// Format high impact
let highSection = 'ALTO IMPACTO:';
if (highImpact.length === 0) {
  highSection += '\n  (ninguno)';
} else {
  highImpact.forEach(event => {
    const hora = new Date(event.date).toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Madrid' });
    const moneda = event.currency || 'N/A';
    const nombre = event.title || event.event || 'Evento desconocido';
    const previo = event.previous !== undefined && event.previous !== null ? event.previous : 'N/A';
    const estimado = event.forecast !== undefined && event.forecast !== null ? event.forecast : 'N/A';
    highSection += `\n• ${hora} | ${moneda} | ${nombre} | Previo: ${previo} | Estimado: ${estimado}`;
  });
}

// Format medium impact
let mediumSection = 'MEDIO IMPACTO:';
if (mediumImpact.length === 0) {
  mediumSection += '\n  (ninguno)';
} else {
  mediumImpact.forEach(event => {
    const hora = new Date(event.date).toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Madrid' });
    const moneda = event.currency || 'N/A';
    const nombre = event.title || event.event || 'Evento desconocido';
    mediumSection += `\n• ${hora} | ${moneda} | ${nombre}`;
  });
}

// Risk windows
const riskSection = 'VENTANAS DE RIESGO HOY: ' + (riskWindows.length > 0 ? riskWindows.join(', ') : 'Ninguna');

const output = `CALENDARIO ECONÓMICO — ${dateStr}\n\n${highSection}\n\n${mediumSection}\n\n${riskSection}`;

return [{ json: { output, riskWindows } }];

// Error Handler - Return empty calendar on failure
const errorMessage = $input.first().json.message || $input.first().json.error || 'Unknown error';
console.error('Calendar fetch failed:', errorMessage);

const today = new Date();
const dateStr = today.toLocaleDateString('es-ES', { 
  weekday: 'long', 
  year: 'numeric', 
  month: 'long', 
  day: 'numeric' 
});

return [{ json: { 
  output: `CALENDARIO ECONÓMICO — ${dateStr}\n\nError al obtener el calendario económico. Inténtelo de nuevo más tarde.`, 
  riskWindows: [],
  error: errorMessage
}}];
